import React, { useState } from 'react';
import { Link, Navigate, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';

const toPrice = (value) => {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : 0;
};

export default function Cart() {
    const { isAuthenticated, isAdmin } = useAuth();
    const { cartItems, cartSummary, updateItem, removeItem, loading } = useCart();
    const navigate = useNavigate();
    const [actionError, setActionError] = useState('');
    const [busyItemId, setBusyItemId] = useState(null);

    if (isAuthenticated && !isAdmin) {
        return <Navigate to="/dashboard/cart" replace />;
    }

    const handleQuantityChange = async (cartItemId, newQuantity) => {
        try {
            setActionError('');
            setBusyItemId(cartItemId);

            if (newQuantity < 1) {
                await removeItem(cartItemId);
            } else {
                await updateItem(cartItemId, newQuantity);
            }
        } catch (error) {
            setActionError(error?.response?.data?.message || error?.message || 'Failed to update cart.');
        } finally {
            setBusyItemId(null);
        }
    };

    const handleRemove = async (cartItemId) => {
        try {
            setActionError('');
            setBusyItemId(cartItemId);
            await removeItem(cartItemId);
        } catch (error) {
            setActionError(error?.response?.data?.message || error?.message || 'Failed to remove item.');
        } finally {
            setBusyItemId(null);
        }
    };

    if (loading) {
        return <div className="loading-container">Loading cart...</div>;
    }

    return (
        <div className="cart-page">
            <h1>Shopping Cart</h1>

            {actionError && <div className="error-message">{actionError}</div>}

            {cartItems.length === 0 ? (
                <div className="empty-cart">
                    <p>Your cart is empty</p>
                    <Link to="/products" className="btn btn-primary">
                        Continue Shopping
                    </Link>
                </div>
            ) : (
                <div className="cart-container">
                    <div className="cart-items">
                        <table className="cart-table">
                            <thead>
                                <tr>
                                    <th>Product</th>
                                    <th>Price</th>
                                    <th>Quantity</th>
                                    <th>Subtotal</th>
                                    <th>Action</th>
                                </tr>
                            </thead>
                            <tbody>
                                {cartItems.map((item) => {
                                    const productId = item?.product?.id || item?.product_id;
                                    const price = toPrice(item?.product?.price);
                                    const quantity = Number(item?.quantity || 0);
                                    const disabled = busyItemId === item.id;

                                    return (
                                        <tr key={item.id}>
                                            <td>
                                                <Link to={`/products/${productId}`} className="product-name">
                                                    {item?.product?.name || 'Product'}
                                                </Link>
                                            </td>
                                            <td>₱{price.toFixed(2)}</td>
                                            <td>
                                                <div className="quantity-control">
                                                    <button
                                                        onClick={() => handleQuantityChange(item.id, quantity - 1)}
                                                        disabled={disabled}
                                                    >
                                                        −
                                                    </button>
                                                    <input
                                                        type="number"
                                                        value={quantity}
                                                        onChange={(e) => handleQuantityChange(item.id, parseInt(e.target.value, 10) || 1)}
                                                        min="1"
                                                        disabled={disabled}
                                                    />
                                                    <button
                                                        onClick={() => handleQuantityChange(item.id, quantity + 1)}
                                                        disabled={disabled}
                                                    >
                                                        +
                                                    </button>
                                                </div>
                                            </td>
                                            <td>₱{(price * quantity).toFixed(2)}</td>
                                            <td>
                                                <button
                                                    className="btn-remove"
                                                    onClick={() => handleRemove(item.id)}
                                                    disabled={disabled}
                                                >
                                                    {disabled ? 'Updating...' : 'Remove'}
                                                </button>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>

                    {cartSummary && (
                        <div className="cart-summary">
                            <h3>Order Summary</h3>

                            <div className="summary-row">
                                <span>Subtotal:</span>
                                <span>₱{toPrice(cartSummary.subtotal).toFixed(2)}</span>
                            </div>

                            <div className="summary-row">
                                <span>Tax (10%):</span>
                                <span>₱{toPrice(cartSummary.tax).toFixed(2)}</span>
                            </div>

                            <div className="summary-row">
                                <span>Shipping:</span>
                                <span>₱{toPrice(cartSummary.shipping).toFixed(2)}</span>
                            </div>

                            <div className="summary-row total">
                                <span>Total:</span>
                                <span>₱{toPrice(cartSummary.total).toFixed(2)}</span>
                            </div>

                            <button
                                className="btn btn-primary btn-block"
                                onClick={() => navigate(isAuthenticated ? '/dashboard/checkout' : '/login')}
                            >
                                Proceed to Checkout
                            </button>

                            <Link to="/products" className="btn btn-secondary btn-block">
                                Continue Shopping
                            </Link>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}